const { execFileSync } = require('child_process')

const PROJECT_REF = 'qsllyeztdwjgirsysgai'
const SUPABASE_URL = `https://${PROJECT_REF}.supabase.co/rest/v1`
const DIRECTUS_DB = 'directus-db-nzli85mk3luzb6u7cnq5fidu'

function serviceKey() {
  const keys = JSON.parse(execFileSync('supabase', ['projects','api-keys','--project-ref',PROJECT_REF,'-o','json'], {encoding:'utf8'}))
  const key = keys.find(k => k.name === 'service_role')?.api_key
  if (!key) throw new Error('No service_role key returned by Supabase CLI')
  return key
}
const SERVICE_KEY = serviceKey()

function psqlJson(sql) {
  const wrapped = `copy (select coalesce(json_agg(q), '[]'::json)::text from (${sql}) q) to stdout`
  const out = execFileSync('docker', ['exec', DIRECTUS_DB, 'psql', '-U', 'directus', '-d', 'directus', '-Atc', wrapped], {encoding:'utf8', maxBuffer: 100 * 1024 * 1024})
  return JSON.parse(out || '[]')
}

async function rest(schema, table, { method='GET', qs='', body, prefer } = {}) {
  const res = await fetch(`${SUPABASE_URL}/${table}${qs ? '?' + qs : ''}`, {
    method,
    headers: {
      apikey: SERVICE_KEY,
      Authorization: `Bearer ${SERVICE_KEY}`,
      'Accept-Profile': schema,
      'Content-Profile': schema,
      ...(body ? { 'Content-Type': 'application/json' } : {}),
      ...(prefer ? { Prefer: prefer } : {}),
    },
    body: body ? JSON.stringify(body) : undefined,
  })
  const text = await res.text()
  let data = null
  try { data = text ? JSON.parse(text) : null } catch { data = text }
  if (!res.ok) throw new Error(`${method} ${schema}.${table} failed ${res.status}: ${JSON.stringify(data).slice(0,1000)}`)
  return { data, count: res.headers.get('content-range') }
}

async function getAll(schema, table, select, extra = '') {
  const out = []
  for (let from = 0; ; from += 1000) {
    const res = await fetch(`${SUPABASE_URL}/${table}?select=${select}${extra ? '&' + extra : ''}`, {
      headers: {
        apikey: SERVICE_KEY,
        Authorization: `Bearer ${SERVICE_KEY}`,
        'Accept-Profile': schema,
        Range: `${from}-${from + 999}`,
      },
    })
    const data = await res.json()
    if (!res.ok) throw new Error(`GET ${schema}.${table} failed ${res.status}: ${JSON.stringify(data).slice(0,1000)}`)
    out.push(...data)
    if (data.length < 1000) return out
  }
}

async function upsert(schema, table, rows, conflict) {
  if (!rows.length) return 0
  let n = 0
  for (let i = 0; i < rows.length; i += 500) {
    const chunk = rows.slice(i, i + 500)
    await rest(schema, table, {
      method: 'POST',
      qs: `on_conflict=${encodeURIComponent(conflict)}`,
      body: chunk,
      prefer: 'resolution=merge-duplicates,return=minimal',
    })
    n += chunk.length
  }
  return n
}

async function insertMissingEmail() {
  const targetIds = new Set((await getAll('crm', 'email_message', 'id')).map(r => r.id))
  const sourceRows = psqlJson(`
    select *
    from crm_email_message
    where id not in (${Array.from(targetIds).map(id => `'${id}'`).join(',') || "'00000000-0000-0000-0000-000000000000'"})
    order by id
  `)
  const rows = sourceRows.map(r => ({
    id: r.id,
    subject: r.subject ?? r.name ?? null,
    sender: r.sender ?? null,
    recipients: r.recipients ?? null,
    received_at: r.received_at ?? null,
    body_preview: r.body_preview ?? null,
    outlook_message_id: r.outlook_message_id ?? null,
    routing_status: r.routing_status ?? null,
