function psqlJson(sql) {
  const wrapped = `select coalesce(json_agg(q), '[]'::json)::text from (${sql}) q`
  const out = execFileSync('docker', ['exec', DIRECTUS_DB, 'psql', '-U', 'directus', '-d', 'directus', '-Atc', wrapped], {encoding:'utf8', maxBuffer: 100 * 1024 * 1024})
